        raise ValueError("Unsupported syntax")

    try:
        return _eval(tree.body)
    except ZeroDivisionError:
        return "Error: Division by zero"
    except OverflowError:
        return "Error: Numerical overflow"
    except MemoryError:
        return "Error: Evaluation ran out of memory"
    except ValueError as e:
        return f"Error: {e}"
    except Exception:
        return "Error: Failed to evaluate expression"


def process_user_query(user_input: str) -> str:
    """
    Process user input by validating and safely evaluating a basic arithmetic expression.
    Returns the result as a string, or 'Error!' if input is untrustworthy or an error occurs.
    """
    try:
        if not isinstance(user_input, str):
            return "Error!"
        expr = user_input.strip()
        if not expr:
            return "Error!"
        if not parse_user_expression(expr):
            return "Error!"
        result = evaluate_safe_expression(expr)
        if isinstance(result, str):
            # evaluation returned an error message
            return "Error!"
        return str(result)
    except Exception:
        return "Error!"

