    if not expr:
        return 'Error!'

    def is_number(val):
        return type(val) in (int, float)

    def is_string(val):
        return isinstance(val, str)

    def eval_node(node):
        if isinstance(node, ast.Expression):
            return eval_node(node.body)

        # Numbers (ints/floats) and strings only
        if isinstance(node, ast.Constant):
